#!/usr/bin/env node
// Generates src/app/core/firebase/firebase.env.generated.ts from
// NG_APP_FIREBASE_* environment variables.
//
// Sources, later wins: .env -> .env.local -> process.env. Vercel/CI inject
// via process.env; local dev uses .env.local. Missing vars become "".
// The generated file is gitignored; firebase.config.ts imports it. Runs via
// the gen:firebase-env npm script (wired into build/start/test) + postinstall.
import { readFileSync, writeFileSync, existsSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

const root = join(dirname(fileURLToPath(import.meta.url)), '..');

function parseDotenv(file) {
  const path = join(root, file);
  if (!existsSync(path)) return {};
  const out = {};
  for (const line of readFileSync(path, 'utf8').split('\n')) {
    const m = line.match(/^\s*(?:export\s+)?([A-Za-z_][A-Za-z0-9_]*)\s*=\s*(.*)$/);
    if (!m) continue;
    let v = m[2].trim();
    if ((v.startsWith('"') && v.endsWith('"')) || (v.startsWith("'") && v.endsWith("'"))) {
      v = v.slice(1, -1);
    }
    out[m[1]] = v;
  }
  return out;
}

const merged = { ...parseDotenv('.env'), ...parseDotenv('.env.local'), ...process.env };

const KEYS = [
  'NG_APP_FIREBASE_API_KEY',
  'NG_APP_FIREBASE_AUTH_DOMAIN',
  'NG_APP_FIREBASE_PROJECT_ID',
  'NG_APP_FIREBASE_STORAGE_BUCKET',
  'NG_APP_FIREBASE_MESSAGING_SENDER_ID',
  'NG_APP_FIREBASE_APP_ID',
  'NG_APP_FIREBASE_MEASUREMENT_ID',
  'NG_APP_FIREBASE_VAPID_KEY',
];

const values = {};
for (const k of KEYS) values[k] = merged[k] ?? '';

// Fail the build on a malformed VAPID key. A truncated/garbled key sails
// silently through to the client, where getToken() throws InvalidAccessError
// (DOMException 15) and web-push registration dies with no server-side signal —
// exactly the failure that motivated this guard. A valid Web Push
// applicationServerKey is an uncompressed P-256 point: 65 bytes (0x04 + X + Y),
// i.e. 87 base64url chars. Empty is allowed (envs without web push).
if (values.NG_APP_FIREBASE_VAPID_KEY) {
  const bytes = Buffer.from(
    values.NG_APP_FIREBASE_VAPID_KEY.trim().replace(/-/g, '+').replace(/_/g, '/'),
    'base64',
  );
  if (bytes.length !== 65 || bytes[0] !== 0x04) {
    throw new Error(
      `[gen-firebase-env] NG_APP_FIREBASE_VAPID_KEY is invalid: decoded to ${bytes.length} ` +
        'bytes (expected 65, first byte 0x04). Re-copy the full Web Push certificate key pair ' +
        'from Firebase Console → Project settings → Cloud Messaging → Web Push certificates.',
    );
  }
}

const out = `// AUTO-GENERATED by scripts/gen-firebase-env.mjs — do not edit, do not commit.
// Firebase web config from NG_APP_FIREBASE_* env (.env.local in dev, Vercel env
// in prod). Missing values are empty strings.
/* eslint-disable */
export const firebaseEnv = ${JSON.stringify(values, null, 2)} as const;
`;

writeFileSync(join(root, 'src/app/core/firebase/firebase.env.generated.ts'), out);

// Also generate the FCM web-push service worker. A service worker can't read
// the Angular env, so the (public) config is inlined; the Firebase web SDK's
// getToken() auto-registers /firebase-messaging-sw.js, and it shows background
// notifications. Gitignored like the env module above; regenerated each build.
let fbVersion = '11.0.0';
try {
  fbVersion = JSON.parse(
    readFileSync(join(root, 'node_modules/firebase/package.json'), 'utf8'),
  ).version;
} catch {
  /* keep the fallback version */
}
const swConfig = {
  apiKey: values.NG_APP_FIREBASE_API_KEY,
  authDomain: values.NG_APP_FIREBASE_AUTH_DOMAIN,
  projectId: values.NG_APP_FIREBASE_PROJECT_ID,
  storageBucket: values.NG_APP_FIREBASE_STORAGE_BUCKET,
  messagingSenderId: values.NG_APP_FIREBASE_MESSAGING_SENDER_ID,
  appId: values.NG_APP_FIREBASE_APP_ID,
};
const sw = `// AUTO-GENERATED by scripts/gen-firebase-env.mjs — do not edit, do not commit.
// Firebase Cloud Messaging service worker: required for web push token
// registration (getToken needs a service worker) and to display background
// notifications. Notification-payload messages auto-display, so no
// onBackgroundMessage handler is needed (which would double-notify).
importScripts('https://www.gstatic.com/firebasejs/${fbVersion}/firebase-app-compat.js');
importScripts('https://www.gstatic.com/firebasejs/${fbVersion}/firebase-messaging-compat.js');

firebase.initializeApp(${JSON.stringify(swConfig)});
firebase.messaging();
`;
writeFileSync(join(root, 'public/firebase-messaging-sw.js'), sw);

const set = KEYS.filter((k) => values[k]).length;
console.log(
  `[gen-firebase-env] firebase.env.generated.ts + public/firebase-messaging-sw.js written (${set}/${KEYS.length} values present)`,
);
